------------------------------------------------------------
----- CREATE PROCEDURE FOR account_info
------------------------------------------------------------
IF OBJECT_ID('[hubspot].[spCreateaccount_info]', 'P') IS NOT NULL
    DROP PROCEDURE [hubspot].[spCreateaccount_info];
GO

CREATE PROCEDURE [hubspot].[spCreateaccount_info]
    @companyName_Clear bit = 0,
    @companyName nvarchar(MAX) = NULL,
    @timeZone_Clear bit = 0,
    @timeZone nvarchar(MAX) = NULL,
    @utcOffsetMilliseconds_Clear bit = 0,
    @utcOffsetMilliseconds nvarchar(MAX) = NULL,
    @dataHostingLocation_Clear bit = 0,
    @dataHostingLocation nvarchar(MAX) = NULL,
    @utcOffset_Clear bit = 0,
    @utcOffset nvarchar(MAX) = NULL,
    @hubType_Clear bit = 0,
    @hubType nvarchar(MAX) = NULL,
    @additionalCurrencies_Clear bit = 0,
    @additionalCurrencies nvarchar(MAX) = NULL,
    @portalId nvarchar(450) = NULL,
    @uiDomain_Clear bit = 0,
    @uiDomain nvarchar(MAX) = NULL,
    @inTrial_Clear bit = 0,
    @inTrial nvarchar(MAX) = NULL,
    @currency_Clear bit = 0,
    @currency nvarchar(MAX) = NULL,
    @__mj_integration_SyncStatus nvarchar(50) = NULL,
    @__mj_integration_LastSyncedAt_Clear bit = 0,
    @__mj_integration_LastSyncedAt datetimeoffset = NULL,
    @__mj_integration_LastSyncedSnapshot_Clear bit = 0,
    @__mj_integration_LastSyncedSnapshot nvarchar(MAX) = NULL,
    @__mj_integration_SyncMessage_Clear bit = 0,
    @__mj_integration_SyncMessage nvarchar(MAX) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    
    INSERT INTO
    [hubspot].[account_info]
        (
            [companyName],
                [timeZone],
                [utcOffsetMilliseconds],
                [dataHostingLocation],
                [utcOffset],
                [hubType],
                [additionalCurrencies],
                [uiDomain],
                [inTrial],
                [currency],
                [__mj_integration_SyncStatus],
                [__mj_integration_LastSyncedAt],
                [__mj_integration_LastSyncedSnapshot],
                [__mj_integration_SyncMessage],
                [portalId]
        )
    VALUES
        (
            CASE WHEN @companyName_Clear = 1 THEN NULL ELSE ISNULL(@companyName, NULL) END,
                CASE WHEN @timeZone_Clear = 1 THEN NULL ELSE ISNULL(@timeZone, NULL) END,
                CASE WHEN @utcOffsetMilliseconds_Clear = 1 THEN NULL ELSE ISNULL(@utcOffsetMilliseconds, NULL) END,
                CASE WHEN @dataHostingLocation_Clear = 1 THEN NULL ELSE ISNULL(@dataHostingLocation, NULL) END,
                CASE WHEN @utcOffset_Clear = 1 THEN NULL ELSE ISNULL(@utcOffset, NULL) END,
                CASE WHEN @hubType_Clear = 1 THEN NULL ELSE ISNULL(@hubType, NULL) END,
                CASE WHEN @additionalCurrencies_Clear = 1 THEN NULL ELSE ISNULL(@additionalCurrencies, NULL) END,
                CASE WHEN @uiDomain_Clear = 1 THEN NULL ELSE ISNULL(@uiDomain, NULL) END,
                CASE WHEN @inTrial_Clear = 1 THEN NULL ELSE ISNULL(@inTrial, NULL) END,
                CASE WHEN @currency_Clear = 1 THEN NULL ELSE ISNULL(@currency, NULL) END,
                ISNULL(@__mj_integration_SyncStatus, 'Active'),
                CASE WHEN @__mj_integration_LastSyncedAt_Clear = 1 THEN NULL ELSE ISNULL(@__mj_integration_LastSyncedAt, NULL) END,
                CASE WHEN @__mj_integration_LastSyncedSnapshot_Clear = 1 THEN NULL ELSE ISNULL(@__mj_integration_LastSyncedSnapshot, NULL) END,
                CASE WHEN @__mj_integration_SyncMessage_Clear = 1 THEN NULL ELSE ISNULL(@__mj_integration_SyncMessage, NULL) END,
                @portalId
        )
    -- return the new record from the base view, which might have some calculated fields
    SELECT * FROM [hubspot].[vwAccount_infos] WHERE [portalId] = @portalId
